/*SELECT text, date_from, date_to, ee, mm, hh, status, created_by, last_updated_by, last_updated_date, last_updated_time, insured_id, incr_seq_no, creation_date FROM PEN_EFKA_DAYS_DLT WHERE INSURED_ID = :P_INSURED_ID AND STATUS = '1' AND ( ( PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE AND PDTA_APPLICATION_YEAR = :P_APPL_YEAR AND APPLICATION_INCR_SEQ_NO = :P_APPL_INCR_SEQ_NO ) OR ( NVL(PDTA_APPLICATION_UNIT_CODE,'0') = '0' AND NVL(PDTA_APPLICATION_YEAR,0) = 0 AND NVL(APPLICATION_INCR_SEQ_NO,0) = 0 ) )
*/
SELECT DISTINCT 1 ORD, B.TEXT,B.DATE_FROM,B.DATE_TO,B.EE,B.MM,B.HH, null trans_descr_alloi_foreis FROM PEN_EFKA_DAYS_HDR A, PEN_EFKA_DAYS_DLT B WHERE A.INSURED_ID = B.INSURED_ID AND A.INSURED_ID = :P_INSURED_ID AND B.PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE AND B.PDTA_APPLICATION_YEAR = :P_APPL_YEAR AND B.APPLICATION_INCR_SEQ_NO = :P_APPL_INCR_SEQ_NO AND TEXT NOT LIKE '%ΣΥΝΟΛ%' AND :p_application_efka_days = 1 UNION SELECT DISTINCT 2 ORD, B.TEXT,B.DATE_FROM,B.DATE_TO,B.EE,B.MM,B.HH, null trans_descr_alloi_foreis FROM PEN_EFKA_DAYS_HDR A, PEN_EFKA_DAYS_DLT B WHERE A.INSURED_ID = B.INSURED_ID AND A.INSURED_ID = :P_INSURED_ID AND B.PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE AND B.PDTA_APPLICATION_YEAR = :P_APPL_YEAR AND B.APPLICATION_INCR_SEQ_NO = :P_APPL_INCR_SEQ_NO AND :p_application_efka_days = 1 AND TEXT LIKE '%ΣΥΝΟΛ%' UNION SELECT DISTINCT 1 ORD, B.TEXT,B.DATE_FROM,B.DATE_TO,B.EE,B.MM,B.HH, null trans_descr_alloi_foreis FROM PEN_EFKA_DAYS_HDR A, PEN_EFKA_DAYS_DLT B WHERE A.INSURED_ID = B.INSURED_ID AND A.INSURED_ID = :P_INSURED_ID AND B.PDTA_APPLICATION_UNIT_CODE IS NULL AND B.PDTA_APPLICATION_YEAR IS NULL AND B.APPLICATION_INCR_SEQ_NO IS NULL AND TEXT NOT LIKE '%ΣΥΝΟΛ%' AND :p_application_efka_days = 0 UNION SELECT DISTINCT 2 ORD, B.TEXT,B.DATE_FROM,B.DATE_TO,B.EE,B.MM,B.HH, null trans_descr_alloi_foreis FROM PEN_EFKA_DAYS_HDR A, PEN_EFKA_DAYS_DLT B WHERE A.INSURED_ID = B.INSURED_ID AND A.INSURED_ID = :P_INSURED_ID AND B.PDTA_APPLICATION_UNIT_CODE IS NULL AND B.PDTA_APPLICATION_YEAR IS NULL AND B.APPLICATION_INCR_SEQ_NO IS NULL AND :p_application_efka_days = 0 AND TEXT LIKE '%ΣΥΝΟΛ%' -- CHRYS 9/4/2024 UNION SELECT 5 ORD, C.COUNTRY_NAME, MIN(TO_DATE('01'||TRIM(LPAD(A.MONTH,2,0))||A.YEAR, 'DDMMRRRR')), MAX(LAST_DAY(TO_DATE('01'||TRIM(LPAD(A.MONTH,2,0))||A.YEAR, 'DDMMRRRR'))), NULL, NULL,SUM(NVL(INSURANCE_DAYS_CALC_FINAL,0)) , D.TRANS_DESCR trans_descr_alloi_foreis FROM PEN_INSURED_DAYS A, COM_PENSION_INSTITUTIONS B, PEN_COUNTRIES C, COM_INSURANCE_HISTORY_TYPES D WHERE A.ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO AND A.STATUS = '1' AND A.PENSION_INST_CODE = B.PENSION_INST_CODE AND B.CNTRY_COUNTRY_CODE = C.COUNTRY_CODE AND C.COUNTRY_CODE != 'GR' AND A.INSHISTYP_TRANS_TYPE = D.TRANS_TYPE GROUP BY C.COUNTRY_NAME, 5,D.TRANS_DESCR -- END CHRYS 9/4/2024 ORDER BY 1,3

