begin

	SELECT START_DATE
	INTO V_START_DATE
  FROM PEN_ACCOUNT
  WHERE Account_No =  :P_Acc_Account_No;

  IF V_START_DATE >= TO_DATE('15072010','DDMMRRRR') THEN  
  		v_text := 'Ο χρόνος απασχόλησης μετά τη συνταξιοδότηση είναι συντάξιμος.
(περ.3 παρ.1 άρθρο 16 Ν.3863/10)';
