      function CF_51Formula return Number is
V_NUM_1 NUMBER;

CURSOR CUR_1 IS
SELECT  TOTAL_AMOUNT
FROM  PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;


CURSOR CUR_NAT IS
SELECT FINAL_NAT_PENSION_AMT 
FROM PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;

CURSOR CUR_ADAP IS
SELECT ADAPODOTIKH_AMT 
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;

V_NAT   NUMBER;
V_ADAP  NUMBER;
begin
 --CHRYS 25/5/2018   RETURN (NVL(:CF_23,0) + NVL(:CF_50,0));
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
 -- COMBAT_dEBUGING('V_NUM_1='||V_NUM_1, 'CHRYS_2711');
  OPEN CUR_NAT;
  FETCH CUR_NAT
  INTO V_NAT;
  CLOSE CUR_NAT;
 -- COMBAT_dEBUGING('V_NAT='||V_NAT, 'CHRYS_2711');
  OPEN CUR_ADAP;
  FETCH CUR_ADAP
  INTO V_ADAP;
  CLOSE CUR_ADAP;
 -- COMBAT_dEBUGING('V_ADAP='||V_ADAP, 'CHRYS_2711');
  --RETURN NVL(V_NUM_1,0) + NVL(:CF_50,0);
  -- CHRYS 27/11/2019 RETURN NVL(V_NAT,0) + NVL(V_ADAP,0)  + NVL(:CF_50,0);
 -- COMBAT_dEBUGING('V_TOTAL ='||(NVL(V_NAT,0) + NVL(V_ADAP,0)  + NVL(:CF_50,0)), 'CHRYS_2711');
 	

 
  RETURN GREATEST ( (NVL(V_NAT,0) + NVL(V_ADAP,0)  + NVL(:CF_50,0)-NVL(:CF_PLAFON,0) ), NVL(V_NUM_1,0)-NVL(:CF_PLAFON,0)) 
  			+ NVL(:CF_56,0); -- CHRYS 5/12/2024
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;

END;

