      function CF_PROD_DESCFormula return Char is
V_RET VARCHAR2(200);

CURSOR C1 IS
Select DECODE(A.DOCUMENT_CODE,'003', 'ΣΥΝΤΑΞΗ ΑΝΑΠΗΡΙΑΣ'
	                           ,'002', 'ΣΥΝΤΑΞΗ ΓΗΡΑΤΟΣ')
From Pen_Award_Type_Flag_Desc A,
     Wrk_In_Out B
Where A.Document_Code        = B.Document_Code
  And B.Protocol_Orgbra_Code = :P_APPL_UNIT_CODE
  And B.Protocol_Year        = :P_APPL_YEAR
  And B.Protocol_No          = :P_APPL_INCR_SEQ_NO
; 


begin

	OPEN C1;
