	CLOSE C1;
	  
	RETURN V_RET;
	
	EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

      function CF_56Formula return Number is
v_NUM NUMBER;
-- CHRYS 3/6/2021    
