      function CF_THEMELIOSIFormula return Number is

CURSOR CUR_INSURED_DAYS IS
SELECT 1 
FROM PEN_INSURED_DAYS
WHERE	ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO;

V_DUMMY NUMBER;
begin
	
	V_DUMMY := 0;
	OPEN	CUR_INSURED_DAYS;
	FETCH	CUR_INSURED_DAYS
	INTO	V_DUMMY;
	CLOSE	CUR_INSURED_DAYS;
	
	RETURN V_DUMMY;
		
  
end;

